from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when a product price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a product quantity is invalid."""


class ProductNotFoundError(ShoppingCartError):
    """Raised when a product cannot be found in the cart."""


class DiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this item before discounts."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Defines the interface for shopping cart discounts."""

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the discount amount for the given subtotal."""


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the percentage discount amount."""
        return subtotal * (self.percentage / Decimal("100"))


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the flat discount amount."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """Manages cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._normalize_product_name(product_name)
        self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_name)
        if existing_item is None:
            self._items[normalized_name] = CartItem(
                product_name=normalized_name,
                unit_price=unit_price,
                quantity=quantity,
            )
            return

        if existing_item.unit_price != unit_price:
            raise InvalidPriceError(
                f"Product '{normalized_name}' already exists with unit price "
                f"{existing_item.unit_price}; received {unit_price}."
            )

        self._items[normalized_name] = replace(
            existing_item,
            quantity=existing_item.quantity + quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._normalize_product_name(product_name)
        self._get_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._normalize_product_name(product_name)
        self._validate_quantity(quantity)

        existing_item = self._get_item(normalized_name)
        self._items[normalized_name] = replace(existing_item, quantity=quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the subtotal before discounts."""
        return sum(
            (item.total_price for item in self._items.values()),
            start=Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount to the cart."""
        if percentage < Decimal("0") or percentage > Decimal("100"):
            raise DiscountError("Percentage discount must be between 0 and 100.")

        self._discount = PercentageDiscount(percentage=percentage)

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat discount to the cart."""
        if amount < Decimal("0"):
            raise DiscountError("Flat discount amount cannot be negative.")

        self._discount = FlatDiscount(amount=amount)

    def calculate_total(self) -> Decimal:
        """Calculate the final total after discounts."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        discount_amount = self._discount.calculate_discount(subtotal)
        return subtotal - discount_amount

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their details."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_item(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise ProductNotFoundError(f"Product '{product_name}' is not in the cart.")

        return self._items[product_name]

    @staticmethod
    def _normalize_product_name(product_name: str) -> str:
        normalized_name = product_name.strip()

        if not normalized_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_name

    @staticmethod
    def _validate_unit_price(unit_price: Decimal) -> None:
        if unit_price <= Decimal("0"):
            raise InvalidPriceError("Unit price must be greater than zero.")

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")
